def select_action(obs: np.ndarray) -> int:
    if obs[101] == 0:
        return 1

    ball_x = obs[99]
    ball_y = obs[101]
    paddle_x = obs[72]

    # Persistent state for velocity estimation
    if not hasattr(select_action, "prev_ball_y"):
        select_action.prev_ball_y = ball_y
        select_action.prev_ball_x = ball_x
        # Initial simple centering
        if ball_x < paddle_x:
            return 3
        elif ball_x > paddle_x:
            return 2
        return 0

    dy = ball_y - select_action.prev_ball_y
    dx = ball_x - select_action.prev_ball_x
    select_action.prev_ball_y = ball_y
    select_action.prev_ball_x = ball_x

    # Use fixed speed when velocity is zero to avoid division issues
    if dy == 0 and dx == 0:
        if ball_x < paddle_x:
            return 3
        elif ball_x > paddle_x:
            return 2
        return 0

    # Phase 1: Predict intercept using reflection model when ball is moving upward
    if dy < 0:
        sim_x = float(ball_x)
        sim_y = float(ball_y)
        vx = float(dx)
        vy = float(dy)
        # Simulate bounces until reaching paddle height (~192)
        while sim_y < 192:
            sim_y += abs(vy)
            sim_x += vx
            # Top wall reflection
            if sim_y > 210:
                sim_y = 210 - (sim_y - 210)
                vy = -vy
            # Side wall reflections
            if sim_x < 0:
                sim_x = -sim_x
                vx = -vx
            elif sim_x > 160:
                sim_x = 320 - sim_x
                vx = -vx
        target_x = int(sim_x)
    else:
        # Ball moving downward — chase it directly with offset
        target_x = ball_x

    # Phase 2: Deadband-based correction with larger tolerance
    distance = abs(target_x - paddle_x)
    if distance > 50:
        if target_x < paddle_x:
            return 3
        else:
            return 2
    elif distance > 20:
        if target_x < paddle_x:
            return 3
        else:
            return 2
    else:
        return 0
